changeSet.sql:
CREATE INDEX idx_channel_user ON channel(user_id) WHERE organization_id IS NULL;
CREATE INDEX idx_channel_org ON channel(organization_id) WHERE organization_id IS NOT NULL;
CREATE INDEX idx_channel_status ON channel(status);
CREATE UNIQUE INDEX uq_channel_user_name ON channel(user_id, lower(name)) WHERE organization_id IS NULL;
CREATE UNIQUE INDEX uq_channel_org_name ON channel(organization_id, lower(name)) WHERE organization_id IS NOT NULL;

COMMENT ON TABLE channel IS 'Stores channels for event streaming';
COMMENT ON COLUMN channel.id IS 'Unique identifier for the channel';
COMMENT ON COLUMN channel.name IS 'Channel name (unique per user for personal, per org for organization)';
COMMENT ON COLUMN channel.description IS 'Optional channel description';
COMMENT ON COLUMN channel.user_id IS 'User who owns (personal) or created (org) this channel';
COMMENT ON COLUMN channel.organization_id IS 'Organization this channel belongs to (null for personal channels)';
COMMENT ON COLUMN channel.status IS 'Channel status (ACTIVE, PAUSED, PENDING_DELETION)';
COMMENT ON COLUMN channel.created_at IS 'Timestamp when the channel was created';
COMMENT ON COLUMN channel.updated_at IS 'Timestamp when the channel was last updated';
COMMENT ON INDEX idx_channel_user IS 'Partial index for personal channels';
COMMENT ON INDEX idx_channel_org IS 'Partial index for organization channels';
COMMENT ON INDEX idx_channel_status IS 'Index for filtering by channel status';
COMMENT ON INDEX uq_channel_user_name IS 'Partial unique constraint for personal channel names (case-insensitive)';
COMMENT ON INDEX uq_channel_org_name IS 'Partial unique constraint for organization channel names (case-insensitive)';
